SELECT state_code, COUNT(sighting_id) AS total_sightings
FROM ufo_sightings
GROUP BY state_code;

SELECT total_sightings
  FROM sighting_statistics
  WHERE state_code = 1;

SELECT MAX(duration) AS max_duration
FROM ufo_sightings
WHERE state_code = 1;

SELECT state_code, total_sightings
FROM sighting_statistics
ORDER BY total_sightings DESC;

SELECT shape_name
FROM sighting_shapes
WHERE shape_id = 1;

SELECT state_code, duration
FROM ufo_sightings
WHERE state_code = 0 AND duration = 0;
